import { FingerDeque, PersistentStack, PersistentQueue } from '../finger-tree';

describe('FingerDeque – construction', () => {
  it('empty() creates an empty deque', () => { const d = FingerDeque.empty<number>(); expect(d.isEmpty).toBe(true); expect(d.size).toBe(0); });
  it('of() with no args is empty', () => { expect(FingerDeque.of<number>().isEmpty).toBe(true); });
  it('from([]) is empty', () => { expect(FingerDeque.from([]).isEmpty).toBe(true); });
  it('of(1) has size 1', () => { expect(FingerDeque.of(1).size).toBe(1); });
  it('of(1,2,3) has size 3', () => { expect(FingerDeque.of(1,2,3).size).toBe(3); });
  it('from Set works', () => { expect(FingerDeque.from(new Set([1,2,3,4,5])).size).toBe(5); });
  it('from Map keys works', () => { const m = new Map([[1,'a'],[2,'b']]); expect(FingerDeque.from(m.keys()).size).toBe(2); });
  it('from generator works', () => { function* gen(){yield 10;yield 20;yield 30;} expect(FingerDeque.from(gen()).toArray()).toEqual([10,20,30]); });
  it('of preserves order', () => { expect(FingerDeque.of(5,4,3,2,1).toArray()).toEqual([5,4,3,2,1]); });
  it('empty isEmpty is true', () => { expect(FingerDeque.empty().isEmpty).toBe(true); });
});

