  it('pop from size 1 gives top 1 rest size 0', () => { let st=PersistentStack.empty<number>(); for(let i=1;i!==2;i++) st=st.push(i); const r=st.pop(); expect(r).toBeDefined(); expect(r![0]).toBe(1); expect(r![1].size).toBe(0); });
