  it('enqueue does not mutate queue of size 1', () => { let q=PersistentQueue.empty<number>(); for(let i=1;i!==2;i++) q=q.enqueue(i); const before=q.toArray(); q.enqueue(999); expect(q.toArray()).toEqual(before); });
  it('dequeue does not mutate queue of size 1', () => { let q=PersistentQueue.empty<number>(); for(let i=1;i!==2;i++) q=q.enqueue(i); const before=q.toArray(); q.dequeue(); expect(q.toArray()).toEqual(before); });
